/**
 * Style Dictionary Config — Tokens Studio Source (Figma)
 *
 * Reads flattened DTCG tokens from design-tokens/tokens-figma.json
 * (generated by scripts/flatten-tokens-studio.js from Tokens Studio export)
 * and produces multi-platform outputs in build/figma/.
 *
 * Uses @tokens-studio/sd-transforms for proper handling of
 * Tokens Studio-specific features (math expressions, composite tokens).
 *
 * Run: node scripts/flatten-tokens-studio.js && npx style-dictionary build --config sd.config.tokens-studio.mjs
 */

import { register } from '@tokens-studio/sd-transforms';
import StyleDictionary from 'style-dictionary';

// Register Tokens Studio transforms (math resolution, dimension px, etc.)
register(StyleDictionary);

export default {
  source: ['design-tokens/tokens-figma.json'],
  preprocessors: ['tokens-studio'],
  platforms: {
    css: {
      transformGroup: 'tokens-studio',
      transforms: ['name/kebab'],
      buildPath: 'build/figma/css/',
      files: [
        {
          destination: 'variables.css',
          format: 'css/variables',
          options: {
            outputReferences: true,
            selector: ':root',
          },
        },
      ],
    },

    js: {
      transformGroup: 'tokens-studio',
      transforms: ['name/camel'],
      buildPath: 'build/figma/js/',
      files: [
        {
          destination: 'tokens.mjs',
          format: 'javascript/es6',
        },
        {
          destination: 'tokens.d.ts',
          format: 'typescript/es6-declarations',
        },
      ],
    },
  },
};
